module top_module(
  input clk,
  input reset,
  output reg out
);parameter STATE_LOW = 2'b00;
  parameter STATE_HIGH = 2'b01;

  reg [1:0] ERR_state;

  always @(posedge clk, posedge reset) begin
    if (reset) begin
      ERR_state <= STATE_LOW;
      out <= 1'b0;
    end else begin
      case (ERR_state)
        STATE_LOW: begin
          ERR_state <= STATE_HIGH;
          out <= 1'b0;
        end
        STATE_HIGH: begin
          ERR_state <= STATE_LOW;
          out <= 1'b0;
        end
      endcase
    end
  end

endmodule
